import { unmarshall } from '@aws-sdk/util-dynamodb';
import type { AttributeValue } from '@aws-sdk/client-dynamodb';
import {
  StepFunctionsInput,
  InsertWorkflowPayload,
  ModifyWorkflowPayload,
  RemoveWorkflowPayload,
} from './types';

export function unmarshallDynamoDB(
  attributeValue: Record<string, AttributeValue> | null | undefined
): Record<string, unknown> | null {
  if (!attributeValue) return null;
  return unmarshall(attributeValue as Record<string, AttributeValue>);
}

export function extractTableName(eventSourceArn: string): string {
  const parts = eventSourceArn.split('/');
  return parts[1] || 'unknown';
}

export function computeChangedFields(
  oldImage: Record<string, unknown> | null,
  newImage: Record<string, unknown> | null
): string[] {
  const changedFields: string[] = [];
  const allKeys = new Set([
    ...Object.keys(oldImage || {}),
    ...Object.keys(newImage || {}),
  ]);

  for (const key of allKeys) {
    const oldVal = oldImage?.[key];
    const newVal = newImage?.[key];
    if (JSON.stringify(oldVal) !== JSON.stringify(newVal)) {
      changedFields.push(key);
    }
  }

  return changedFields;
}

export function toInsertPayload(input: StepFunctionsInput): InsertWorkflowPayload {
  const keys = unmarshallDynamoDB(input.keys) as Record<string, string>;
  const data = unmarshallDynamoDB(input.newImage) || {};

  return {
    id: keys.pk,
    sortKey: keys.sk,
    data,
    eventId: input.eventId,
    timestamp: input.timestamp,
  };
}

export function toModifyPayload(input: StepFunctionsInput): ModifyWorkflowPayload {
  const keys = unmarshallDynamoDB(input.keys) as Record<string, string>;
  const before = unmarshallDynamoDB(input.oldImage) || {};
  const after = unmarshallDynamoDB(input.newImage) || {};
  const changedFields = computeChangedFields(before, after);

  return {
    id: keys.pk,
    sortKey: keys.sk,
    before,
    after,
    eventId: input.eventId,
    timestamp: input.timestamp,
    changedFields,
  };
}

export function toRemovePayload(input: StepFunctionsInput): RemoveWorkflowPayload {
  const keys = unmarshallDynamoDB(input.keys) as Record<string, string>;
  const deletedData = unmarshallDynamoDB(input.oldImage) || {};

  return {
    id: keys.pk,
    sortKey: keys.sk,
    deletedData,
    eventId: input.eventId,
    timestamp: input.timestamp,
  };
}
